INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0206623M$$, 2027, $$This Program Element (PE) provides a collective of USMC Projects that represent a comprehensive effort to modernize and enhance the warfighting capabilities of the
Marine Corps across various domains. They focus on equipping Marines with advanced combat systems, including modernized vehicles, improved infantry weapons
and optics, enhanced ballistic protection, and advanced fire support capabilities like the LW155 howitzer and HIMARS. A recurring theme is the emphasis on leveraging
 technology to improve lethality, survivability, and situational awareness while also reducing logistical burdens and operational costs.
 Beyond direct combat enhancements, a significant portion of these projects supports the Marine Corps' ability to train effectively, operate in diverse environments, and
 sustain operations in contested areas. This includes the development of realistic training simulations, rigorous testing of amphibious and robotic systems, providing
 aerial resupply solutions, ensuring the availability of advanced munitions, improving mobility in distributed operations, and supporting specialized reconnaissance
 missions. The focus on low-cost, non-developmental items and coordination with other services highlights the commitment to efficient resource utilization and
 maximizing the impact of investments in Marine Corps readiness$$, $$The Cold Weather Mountaineering (CWM) program enhances Marine combat effectiveness and survivability in harsh environments. Funded by Congressional
appropriations, our mission is to rapidly identify, test, and evaluate state-of-the-art commercial-off-the-shelf (COTS) and non-developmental items (NDI). By collaborating
with joint and other service partners, we ensure the adoption of low-cost, high-performance solutions. Successful items are transitioned to Marine Corps operational
accounts, directly resulting in a lighter, more mobile, and better-protected force equipped with the best technology available.

B. Accomplishments/Planned Programs ($ in Millions)                                                                   FY 2025 FY 2026
Congressional Add: Cold Weather and Mountaineering                                                                       0.000   2.413
